/*
====================================================================
Design system and global styles for Rolling Plains Dentistry
Aesthetic: traditional medical / corporate, classic serif headings,
clean sans-serif UI, strong teals and greens, soft shadows.
====================================================================
*/

:root {
    /* Core palette (from design) */
    --color-primary-teal: #005D63;
    --color-primary-green: #5A8A47;

    --color-secondary-olive: #8FA75D;
    --color-secondary-teal: #007A80;

    --color-neutral-white: #FFFFFF;
    --color-neutral-offwhite: #F7F7F5;
    --color-neutral-text: #222222;

    --color-semantic-success: #4F8C46;
    --color-semantic-error: #C0392B;
    --color-semantic-warning: #F1C40F;
    --color-semantic-info: #006B74;

    /* Typography */
    --font-heading: 'Lora', Georgia, serif;
    --font-body: 'Source Sans 3', -apple-system, BlinkMacSystemFont, 'Helvetica Neue', Arial, sans-serif;

    --font-size-base: 16px;
    --font-size-h1: 2.25rem; /* 36px */
    --font-size-h2: 1.75rem; /* 28px */
    --font-size-h3: 1.375rem; /* 22px */
    --font-size-body: 1rem;  /* 16px */
    --font-size-small: 0.8125rem; /* 13px */

    --line-height-tight: 1.2;
    --line-height-normal: 1.5;
    --line-height-relaxed: 1.7;

    /* Spacing scale (8px base) */
    --space-0: 0;
    --space-1: 4px;
    --space-2: 8px;
    --space-3: 16px;
    --space-4: 24px;
    --space-5: 32px;
    --space-6: 48px;
    --space-7: 64px;

    /* Shadows and radii */
    --shadow-soft: 0 12px 30px rgba(0, 0, 0, 0.16);
    --shadow-header: 0 3px 6px rgba(0, 0, 0, 0.18);

    --radius-soft: 4px;

    /* Layout */
    --max-width: 1160px;
}

/* Global reset-ish rules */
* {
    box-sizing: border-box;
}

html {
    font-size: var(--font-size-base);
    scroll-behavior: smooth;
}

body {
    margin: 0;
    padding: 0;
    font-family: var(--font-body);
    font-size: var(--font-size-body);
    line-height: var(--line-height-normal);
    color: var(--color-neutral-text);
    background-color: var(--color-neutral-offwhite);
}

img {
    max-width: 100%;
    height: auto;
}

a {
    color: var(--color-primary-teal);
    text-decoration: none;
}

a:hover,
a:focus {
    text-decoration: underline;
}

h1, h2, h3, h4, h5, h6 {
    font-family: var(--font-heading);
    color: var(--color-neutral-text);
    margin-top: 0;
}

p {
    margin-top: 0;
    margin-bottom: var(--space-3);
}

/* Layout helpers */

.site-shell {
    min-height: 100vh;
    display: flex;
    flex-direction: column;
}

.container {
    width: 100%;
    max-width: var(--max-width);
    margin-left: auto;
    margin-right: auto;
    padding-left: var(--space-3);
    padding-right: var(--space-3);
}

.site-content {
    flex: 1 0 auto;
    background-color: var(--color-neutral-white);
    padding-top: var(--space-6);
    padding-bottom: var(--space-6);
}

/* Skip link */

.skip-link {
    position: absolute;
    left: -9999px;
    top: auto;
    width: 1px;
    height: 1px;
    overflow: hidden;
    z-index: 100;
    background-color: var(--color-primary-teal);
    color: var(--color-neutral-white);
    padding: var(--space-2) var(--space-3);
    border-radius: var(--radius-soft);
}

.skip-link:focus {
    left: 50%;
    top: 8px;
    width: auto;
    height: auto;
    transform: translateX(-50%);
}

/* ================================================================
   Header
   ================================================================ */

.site-header {
    flex-shrink: 0;
    background-color: var(--color-neutral-white);
    box-shadow: var(--shadow-header);
}

/* Top band with subtle image/gradient background */
.header-hero {
    position: relative;
    padding-top: var(--space-3);
    padding-bottom: var(--space-5);
    /* Simulated photo + teal overlay to match design */
    background-image:
        linear-gradient(180deg, rgba(0, 93, 99, 0.45), rgba(0, 93, 99, 0.05)),
        linear-gradient(90deg, #e0e8e3, #f3f3f1);
    background-size: cover;
    background-position: center;
}

.header-hero-inner {
    display: flex;
    align-items: flex-start;
    justify-content: space-between;
    gap: var(--space-4);
}

/* Logo card overlapping nav bar */
.logo-slot {
    position: relative;
    z-index: 3;
}

.site-logo {
    display: inline-block;
    background-color: var(--color-neutral-white);
    padding: var(--space-4) var(--space-5);
    box-shadow: var(--shadow-soft);
    border-radius: 2px;
    text-transform: uppercase;
    letter-spacing: 0.12em;
    font-family: var(--font-body);
    font-weight: 600;
    color: var(--color-primary-teal);
}

.logo-line {
    display: block;
}

.logo-line-primary {
    font-size: 0.875rem;
}

.logo-line-secondary {
    margin-top: var(--space-1);
    font-size: 0.8125rem;
    color: var(--color-secondary-olive);
}

/* Utility area: appointment CTA, location buttons, phone list */

.header-utility {
    display: flex;
    flex-direction: column;
    align-items: flex-end;
    gap: var(--space-2);
    font-size: 0.875rem;
}

.header-utility-buttons {
    display: flex;
    gap: var(--space-2);
    flex-wrap: wrap;
    justify-content: flex-end;
}

.header-phones {
    margin-top: var(--space-1);
    text-align: right;
}

.phone-row {
    display: flex;
    align-items: center;
    justify-content: flex-end;
    gap: var(--space-1);
    color: var(--color-neutral-white);
    text-shadow: 0 1px 2px rgba(0, 0, 0, 0.25);
}

.phone-row::before {
    content: '\260E'; /* telephone glyph */
    font-size: 0.8rem;
    margin-right: 2px;
}

.phone-label {
    font-weight: 600;
}

.phone-number {
    color: var(--color-neutral-white);
    text-decoration: none;
}

.phone-number:hover,
.phone-number:focus {
    text-decoration: underline;
}

/* Buttons (shared) */

.btn {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    padding: 0.55rem 1.4rem;
    border-radius: var(--radius-soft);
    border: 1px solid transparent;
    font-family: var(--font-body);
    font-weight: 600;
    font-size: 0.8125rem;
    letter-spacing: 0.12em;
    text-transform: uppercase;
    text-decoration: none;
    cursor: pointer;
    white-space: nowrap;
}

.btn-label {
    display: inline-block;
}

.btn-primary {
    background-color: var(--color-secondary-teal);
    border-color: var(--color-secondary-teal);
    color: var(--color-neutral-white);
}

.btn-primary:hover,
.btn-primary:focus {
    background-color: var(--color-primary-teal);
    border-color: var(--color-primary-teal);
}

.btn-secondary {
    background-color: var(--color-secondary-olive);
    border-color: var(--color-secondary-olive);
    color: var(--color-neutral-white);
}

.btn-secondary:hover,
.btn-secondary:focus {
    background-color: var(--color-primary-green);
    border-color: var(--color-primary-green);
}

.header-cta {
    box-shadow: 0 4px 8px rgba(0, 0, 0, 0.18);
}

/* Main navigation bar */

.main-nav-wrapper {
    position: relative;
    z-index: 2;
    background-color: var(--color-primary-teal);
    box-shadow: 0 6px 10px rgba(0, 0, 0, 0.22);
}

.nav-container {
    display: flex;
    align-items: center;
    justify-content: space-between;
}

/* Mobile toggle (checkbox + label) */

.nav-toggle-checkbox {
    display: none;
}

.nav-toggle-label {
    display: none; /* hidden on desktop, shown via media query */
    flex-direction: row;
    align-items: center;
    gap: 6px;
    color: var(--color-neutral-white);
    cursor: pointer;
    padding-top: 0.75rem;
    padding-bottom: 0.75rem;
}

.nav-toggle-bar {
    width: 18px;
    height: 2px;
    background-color: var(--color-neutral-white);
    border-radius: 2px;
}

.nav-toggle-text {
    font-size: 0.75rem;
    letter-spacing: 0.1em;
    text-transform: uppercase;
    font-weight: 600;
}

/* Nav list */

.main-nav {
    flex: 1 1 auto;
}

.main-nav-list {
    list-style: none;
    margin: 0;
    padding: 0;
    display: flex;
    align-items: center;
    justify-content: center;
    gap: var(--space-4);
}

.main-nav-item {
    margin: 0;
}

.main-nav-link {
    display: block;
    padding-top: 0.95rem;
    padding-bottom: 0.95rem;
    color: var(--color-neutral-white);
    font-family: var(--font-body);
    font-size: 0.8125rem;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: 0.16em;
    text-decoration: none;
}

.main-nav-link:hover,
.main-nav-link:focus {
    text-decoration: none;
    border-bottom: 3px solid var(--color-secondary-olive);
}

/* Active state hook (page-level class can be added) */

.main-nav-link.is-active {
    border-bottom: 3px solid var(--color-secondary-olive);
}

/* ================================================================
   Footer
   ================================================================ */

.site-footer {
    margin-top: var(--space-6);
    background-color: var(--color-neutral-offwhite);
    border-top: 4px solid var(--color-primary-green);
    color: var(--color-neutral-text);
}

.footer-main {
    padding-top: var(--space-6);
    padding-bottom: var(--space-5);
}

.footer-grid {
    display: grid;
    grid-template-columns: repeat(3, minmax(0, 1fr));
    gap: var(--space-5);
}

.footer-column {
    min-width: 0;
}

.footer-heading {
    margin: 0 0 var(--space-2) 0;
    font-family: var(--font-heading);
    font-size: 1rem;
    text-transform: uppercase;
    letter-spacing: 0.16em;
    color: var(--color-primary-teal);
}

.footer-nav {
    list-style: none;
    margin: 0;
    padding: 0;
}

.footer-nav-item {
    margin-bottom: var(--space-1);
}

.footer-link {
    display: inline-block;
    padding-top: 2px;
    padding-bottom: 2px;
    font-size: 0.875rem;
    color: var(--color-neutral-text);
    text-decoration: none;
}

.footer-link:hover,
.footer-link:focus {
    color: var(--color-primary-teal);
    text-decoration: underline;
}

.footer-bottom {
    background-color: var(--color-primary-teal);
    color: var(--color-neutral-white);
    padding-top: 0.75rem;
    padding-bottom: 0.75rem;
}

.footer-bottom-inner {
    display: flex;
    align-items: center;
    justify-content: center;
}

.footer-copy {
    margin: 0;
    font-size: 0.75rem;
}

/* ================================================================
   Responsive behavior
   ================================================================ */

@media (max-width: 960px) {
    .header-hero-inner {
        flex-direction: column;
        align-items: flex-start;
        gap: var(--space-3);
    }

    .header-utility {
        align-items: flex-start;
    }

    .header-utility-buttons {
        justify-content: flex-start;
    }
}

@media (max-width: 900px) {
    .nav-container {
        flex-wrap: wrap;
        align-items: flex-start;
    }

    .nav-toggle-label {
        display: inline-flex;
    }

    .main-nav {
        width: 100%;
        display: none;
    }

    .nav-toggle-checkbox:checked ~ .main-nav {
        display: block;
    }

    .main-nav-list {
        flex-direction: column;
        align-items: flex-start;
        gap: 0;
    }

    .main-nav-link {
        padding-top: 0.75rem;
        padding-bottom: 0.75rem;
        padding-left: 0;
    }
}

@media (max-width: 720px) {
    .site-logo {
        padding: var(--space-3) var(--space-4);
    }

    .header-hero {
        padding-bottom: var(--space-4);
    }

    .footer-grid {
        grid-template-columns: 1fr;
    }
}

@media (max-width: 480px) {
    .header-utility-buttons {
        flex-direction: column;
        align-items: stretch;
    }

    .header-utility-buttons .btn {
        width: 100%;
        justify-content: center;
    }
}
